var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"제발…….","JPN":"頼む……","ENG":"Please...","TWN":"拜託……"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"제발… 늦어서는 안 돼…!","JPN":"頼むから……間に合ってくれ……！","ENG":"Please... I can't be late...!","TWN":"拜託……千萬要趕上……！"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그레이스 경, 어디 계십니까!","JPN":"グレース卿、どこですか！","ENG":"Dame Grace, where are you?!","TWN":"葛瑞絲小姐，你在哪裡！"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그레이스 경!!","JPN":"グレース卿！！","ENG":"Dame Grace!!","TWN":"葛瑞絲小姐！"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"본녀는 여기 있으니, 그리 서두르실 필요 없습니다.","JPN":"私はここにいます。そう焦る必要はありません。","ENG":"I am here. There's no need to be in such a rush.","TWN":"我就在這裡，不必那麼著急。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"아…!","JPN":"あ……！","ENG":"Ah...!","TWN":"啊…！"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"숨을 돌리시지요. 그리 급해서야 나아갈 발을 헛디딜 뿐입니다.","JPN":"落ち着いてください。そんなに急いでいては、つまずきますよ。","ENG":"Take a moment to breathe. If you hurry, your steps will falter.","TWN":"稍微喘口氣吧。太過急躁只會讓你步伐不穩。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"여기서 이러고 계실 때가 아닙니다. 서둘러 이곳을 빠져나가야 해요!","JPN":"こうしている場合ではありません。早くここから出ないと！","ENG":"This isn't the time for calm! You need to leave, now!","TWN":"現在不是待在這裡的時候。我們必須趕快離開這裡！"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"마왕 네헤모트가 이곳을 습격했습니다!","JPN":"魔王ネヘモトがここを襲撃しました！","ENG":"The Demon Lord Nehemoth is attacking this place!","TWN":"魔王貝赫莫特襲擊了這裡！"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"아뇨. 그럴 필요는 없습니다.","JPN":"いいえ。その必要はございません。","ENG":"No. That won't be necessary.","TWN":"不，不需要那樣。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"경께서 다다르신 이곳은 이야기의 종착점이니까요.","JPN":"卿がたどり着いたここが、物語の終着点なのですから。","ENG":"You've arrived at the end of the story.","TWN":"因為你抵達的這個地方就是故事的終點。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……네?","JPN":"……はい？","ENG":"...What?","TWN":"……嗯？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그게… 갑자기 무슨 말씀이십니까?","JPN":"いきなり……何の話ですか？","ENG":"Wait... What are you talking about all of a sudden?","TWN":"你突然說什麼呢？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"이미 눈치채시지 않았습니까? 과거 별의 인도자는 이곳에서 죽음을 맞이했습니다.","JPN":"すでにお気づきなのでは？　過去、星の導き手はここで命を落としました。","ENG":"Surely you've realized it by now. The previous Star Guide met their end here.","TWN":"你難道還沒有察覺嗎？過去在這裡，星之引導者迎來了死亡。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그러니 더 이상 도망칠 필요도, 나아갈 필요도 없지요.","JPN":"ですので、もう逃げる必要も、進む必要もありません。","ENG":"So there's no more need to flee, and no reason to press forward.","TWN":"所以現在既不需要逃避，也不需要前進了。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"하, 하지만 그레이스 경께서는 기사단의 창립자가 아니십니까?","JPN":"で、ですがグレース卿は騎士団の創立者ではないですか。","ENG":"But Dame Grace, you're the founder of the Order, aren't you?","TWN":"下，但是葛瑞絲小姐不是騎士團的創始人嗎？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"여기가 끝이라면, 그런 건…….","JPN":"ここが終わりなら、それは……","ENG":"If this is the end, then...","TWN":"如果這裡是終點，那就……"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"간단한 이야기입니다. 제국에 이어져야 할 별이 마왕의 힘으로 뒤틀렸지요.","JPN":"簡単な話です。帝国に継がれるべきの星が、魔王の力により歪曲されました。","ENG":"It's a simple story. The star that should have guided the Empire was twisted by the Demon Lord's power.","TWN":"這是一個簡單的故事。應與帝國相連的星星被魔王的力量扭曲了。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"기사단의 설립은 별의 인도자를 중심으로 열두 가문의 정의로운 맹세라 알려져 있으나…….","JPN":"騎士団の設立は星の導き手を中心とした、12家門の正義の誓いであると知られておりますが……","ENG":"The founding of the Order is said to have been a noble vow by the twelve houses, centered around the Star Guide...","TWN":"騎士團的成立是以星之引導者為中心的十二家族的正義誓言而聞名……"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"현실은 미련이 남아 과거를 답습했을 뿐입니다.","JPN":"現実は未練がましく過去を繰り返していただけです。","ENG":"But in truth, it was just a repetition of the past, driven by lingering regrets.","TWN":"現實只是因為留戀而重複過去罷了。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그런 허망한 이야기예요.","JPN":"そんな虚しい物語なのです。","ENG":"A hollow tale.","TWN":"那是個荒謬的故事。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"평소와는 다르십니다, 그레이스 경.","JPN":"いつもとは違うではありませんか、グレース卿。","ENG":"You're not yourself, Dame Grace.","TWN":"你和平時不太一樣，葛瑞絲小姐。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"갑자기 그런 말씀을 한들, 저는…….","JPN":"いきなりそんなことを言われても、私は……","ENG":"Even if you say all this now, I...","TWN":"突然這樣說的話，我……"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};